MultiLanguageSpellData['nl'][465999] = {name = "Crimson Armored Growler", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Sommige Goblins verwijzen liefdevol naar getrainde hyena's als 'Growlers.' Deze is dol op graven.\" Leverancier: Rocco Razzboom Zone: Undermine Cost: 8125"}
MultiLanguageSpellData['nl'][466000] = {name = "Darkfuse Chompactor", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Gezien de Top Hond onder Stix's Junkyard Hyenas, het heeft een beet kracht sterk genoeg om te verpletteren wat - of wie - Gallywix wil verwijderd.\" Vendor: Ando de Gat Zone: Bevrijding van Undermine Kosten: 500"}
MultiLanguageSpellData['nl'][466001] = {name = "Blackwater Bonecrusher", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Beste houd die botten voor jezelf als je niet wilt dat ze verpletterd.\" Drop: Blackwater Trove Zone: Undermine"}
MultiLanguageSpellData['nl'][466002] = {name = "Violet Armored Growler", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Smaks weet wel wat van hyena's. Regel nummer één: hou je handen weg van die tanden!\" Leverancier: Smaks Topskimmer Zone: Undermine Cost: 8125"}
MultiLanguageSpellData['nl'][466006] = {name = "Grote vuilnisbelt", additional_info = nil}
MultiLanguageSpellData['nl'][466007] = {name = "Bomschop", additional_info = "Instant [q]Crawler Bombs dragen een stevige bom behuizing voor bescherming, het verminderen van alle schade die ze nemen met 99%. Ze ontploffen alleen bij contact met hun doelwit, waardoor 300 brandschade wordt toegebracht aan spelers binnen 5 meter."}
MultiLanguageSpellData['nl'][466011] = {name = "Flarendo de Furious", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De VIP van VIP's in het Gallagio heeft zijn voordelen, waaronder de sleutels van deze voormalige koning van Carnage. Met geavanceerde goblintechnologie kan hij meer dan 100 meter per liter bereiken!\" Leverancier: Ando de Gat Zone: Bevrijding van ondermijnkosten: 777"}
MultiLanguageSpellData['nl'][466012] = {name = "Onweersbui", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Gevonden van de tribunes van de Ketel tijdens een bijzonder gruwelijke botsing. Op de vraag of het een blindganger was, antwoordde Torq's operator simpelweg: 'Waarschijnlijk?'\" Leverancier: Ando de Gat Zone: Bevrijding van Undermine Kosten: 500"}
MultiLanguageSpellData['nl'][466013] = {name = "Ochre levering Raket", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Haal pakketten en passagiers van punt A naar B in stijl!\" Leverancier: Shredz the Scrapper Zone: Undermine Cost: 11375"}
MultiLanguageSpellData['nl'][466014] = {name = "Steamwheedle Supplier", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Verbetert u met een snelle reis, of uw vijanden met een grote explosie!\" Drop: Stoomwheedle Trove Zone: Undermine"}
MultiLanguageSpellData['nl'][466016] = {name = "De Topskimmer Special", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Smaks weet zeker dat deze raket niet zal ontploffen tijdens de vlucht. Absoluut. Absoluut. 100%. Zeker.\" Leverancier: Smaks Topskimmer Zone: Undermine Cost: 11375"}
MultiLanguageSpellData['nl'][466017] = {name = "Innovatieonderzoeker", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Wanneer het beste pad naar een goed idee echt snel gaat.\" Leverancier: Skedgit Cinderbangs Zone: Undermine Cost: 25"}
MultiLanguageSpellData['nl'][466018] = {name = "Donkerfuse-afbraakapparaat", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Uitstekend in het maken van een puinhoop van dingen. Niet zo goed in opruimen.\" Leverancier: Sitch Lowdown Zone: Undermine Cost: 11375"}
MultiLanguageSpellData['nl'][466019] = {name = "Blackwater Shredder Deluxe Mk 2", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Beste niet te vragen wat er met Mk 1 is gebeurd.\" Leverancier: Boatswain HardeeZone: UndermineCost: 8125"}
MultiLanguageSpellData['nl'][466020] = {name = "Gepersonaliseerde Goblin SCRAPper", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Goblin Shredders hebben keer op keer bewezen nuttig te zijn in vele toepassingen, zoals in logging en transport. Dit model is hergebruikt voor gebruik door S.C.R.A.P..\" Drop: Sifted Pile of Scrap Zone: Undermine"}
MultiLanguageSpellData['nl'][466021] = {name = "Violet Goblin Shredder", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Deze shredder is liefdevol geschilderd met een niet-corrosieve verf om een blijvende glans te garanderen.\" Drop: Shipping and Handling Zone: Undermine"}
MultiLanguageSpellData['nl'][466022] = {name = "Risicocoördinator", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Gebouwd om een Venture-gerelateerde operatie vanuit de frontlinies te beheren.\" Drop: Venture Co. Trove Zone: Ondermijning"}
MultiLanguageSpellData['nl'][466023] = {name = "Asset Advocator", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Het verzekeren van anderen dat uw activa precies zijn waar ze moeten zijn.\" Leverancier: Skedgit CinderbangsZone: UndermineCost: 25"}
MultiLanguageSpellData['nl'][466024] = {name = "Bilgewater Bombardier", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Voor snel transport van Kartel handelsgoederen en andere zeer vluchtige stoffen.\" Drop: Bilgewater Trove Zone: Undermine"}
MultiLanguageSpellData['nl'][466025] = {name = "Marge Manipulator", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Zorgen dat er altijd een marginale afstand is tussen jou en de rotsbodem.\" Leverancier: Skedgit Cinderbangs Zone: Undermine Cost: 25"}
MultiLanguageSpellData['nl'][466026] = {name = "Salved Goblin Gazillionaire's Flying Machine", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Zodra het waardevolle bezit van elite goblin samenleving, deze vliegende machine werd helaas gedegradeerd naar de schroothoop na iets groters, helderder, en meer explosieve kwam op de markt.\" Drop: Gallagio Garbage Zone: Undermine"}
MultiLanguageSpellData['nl'][466027] = {name = "Darkfuse Spy-Eye", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Perfect voor de op-en-komer die de ladder wil beklimmen door het bedrijf van iedereen hun bedrijf te maken.\" World Quest: Darkfuse Precipitant Zone: Undermine"}
