MultiLanguageSpellData['nl'][467024] = {name = "Kaja'Cola Carrier", additional_info = "[q]Mislaid Curiosities hebben nu een 35% kans om 1 Kaja'Cola te bevatten en eenmaal per delve roept Brann nu een Kaja'6-Pack op bij het maken van kampvuren. Er zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld."}
MultiLanguageSpellData['nl'][467026] = {name = "Goblomagnetische bounzing grenade", additional_info = "[q]Brann heeft een kans tijdens de strijd om een GMB granaat te gooien op een vijandelijke doel omgaan met matige Natuurschade met een 20% kans om te verdoven voor 1,5 sec. Dit heeft een kans van 25% om een nieuw doel te bereiken. De granaat kan veilig op partijleden stuiteren."}
MultiLanguageSpellData['nl'][467029] = {name = "Impact Conversie Matrix", additional_info = "Brann activeert de conversiematrix voor 10 sec. Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire status en splitsen tussen partij leden. Na de conversie matrix bevoegdheden naar beneden, de primaire status buff blijft gedurende 10 sec. Dit effect kan niet meer dan eenmaal per 2 minuten optreden."}
