MultiLanguageSpellData['nl'][467033] = {name = "L00T RAID-R", additional_info = "[q]Elke 60 sec of 5 sec na het invoeren van de strijd, scan het milieu markeren van de verkeerde nieuwsgierigheid en het maken van vijanden onder 95% gezondheid nemen 4% meer schade voor 10 sec."}
MultiLanguageSpellData['nl'][467034] = {name = "Reverse Engineered Goblin Death Bomb", additional_info = "[q]Wanneer de gezondheid van een speler tijdens het gevecht onder de 50% daalt, gooit Brann een gigantische bom die ontploft bij impact. De explosie slaat terug en vertraagt de omliggende vijanden door 45% voor 5 sec en geneest nabijgelegen partijleden voor 35% van hun maximale gezondheid. Kan alleen elke 1,5 min. voorkomen."}
MultiLanguageSpellData['nl'][467035] = {name = "Comisch Grote Magneet", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, is er een 100% kans om te magnetiseren verworpen Plating aan partijleden die hen 5% van hun maximale gezondheid als een schild dat regenereert uit de strijd. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][467036] = {name = "Raketwerk voor biobrandstoffen", additional_info = "[q]Party leden zijn uitgerust met Biofuel Rocket Gear. Biofuel Elke vijand gedood brandstoffen de Biofuel Raket Gear verhogen Beweging Snelheid met 2% en Haste met 2% voor 10 sec, stapelen tot 10 keer."}
MultiLanguageSpellData['nl'][467037] = {name = "Pinged Augment Chip", additional_info = "De maximale gezondheid van [q]Brann wordt met 4% verhoogd en zijn schade en genezing met 20% verhoogd. Tijdens het gevecht, Brann kan worden het doelwit door mechanische bots die fixeren op hem die kan worden vernietigd of verdoofd. Als ze Brann bereiken, zal hij 30% van zijn maximale gezondheid in schade lijden en verdoofd zijn gedurende 5 sec."}
