MultiLanguageSpellData['nl'][470059] = {name = "Te veel Arcane", additional_info = "Gekanaliseerd (1 uur cast) [q]Arcanotron lanceert een arcane bom op een nabijgelegen locatie. Als de bom de grond raakt, ontploft hij, waardoor 1755 Arcane schade toebrengt aan alle spelers. Als de bom een speler raakt veroorzaakt het 585 Arcane schade, verhoogt de speler arcane schade genomen met 10% voor 40 sec, en Arcanotron lanceert een andere bom die de grond sneller zal slaan. Arcane Overcharge zal minder schade toebrengen aan de inval voor elke bom die werd gevangen."}
MultiLanguageSpellData['nl'][470061] = {name = "Statische lading", additional_info = "Onbeperkt bereik Instant [q]Torq's pak versterkt de elektrische ladingen gegenereerd binnen 70 meter. Tot de volgende Colossal Clash, een elektrische lading cursussen door spelers die in het bereik komen, waardoor 117391 Natuur schade elke 1 sec.. Bovendien, terwijl in het bereik, de lading groeit wanneer het doel beweegt en degradeert wanneer ze stationair. Bij maximale lading barst het uit in een Static Discharge."}
