MultiLanguageSpellData['nl'][470479] = {name = "Diabole ritueel", additional_info = "Instant [q]Destruction Casting Chaos Bolt, Rain of Fire, of Shadowburn verleent Diabolic Ritual voor 20 sec. Als Diabole Ritual al actief is, wordt de duur ervan met 1 sec verminderd. Als het duivelse ritueel afloopt, krijg je demonische kunst, waardoor je volgende Chaos Bolt, Rain of Fire, of Shadowburn een Overlord, Moeder van Chaos, of Pit Lord roept die een verwoestende aanval op je vijanden loslaat. Demonologie Het uitgeven van een Soul Shard aan een schadelijke spreuk verleent Diabole Ritueel voor 20 sec. Terwijl Diabole Ritual actief is, vermindert elke Soul Shard besteed aan een schadelijke spreuk zijn duur met 1 sec. Als het duivelse ritueel afloopt, krijg je demonische kunst, waardoor je volgende Hand van Gul'dan een Overlord, Moeder van Chaos, of Pit Heer roept die een verwoestende aanval op je vijanden loslaat."}
