MultiLanguageSpellData['nl'][473707] = {name = "Gadgets met elektro-aangedreven kenmerken", additional_info = "De apparatuur van [q]Brann is verbeterd met geavanceerde technische upgrades. Electro-Charged Shield Effectieve genezing gedaan aan Brann pulseert als Natuur schade aan nabijgelegen vijanden. Elektro-bekrachtigde pistool Elk schot ontladingen een elektrische stroom, boog door nabijgelegen vijanden en het verminderen van hun aanval snelheid. Brann genezen laadt zijn pistool op om meer schade aan te richten. Electro-Charged Shotgun Elke vijandelijke aanval heeft een kans om neergeslagen te worden. Brann genezen laadt zijn geweer op om meer schade aan te richten."}
