MultiLanguageSpellData['nl'][474572] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Kaja'Cola Carrier [q]Mislaid Curiosities hebben nu een 35% kans om 1 Kaja'Cola en een keer per delve Brann nu roept een Kaja'6-Pack bij het creëren van kampvuren. Er zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474573] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Comicly Large Magnet [q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, is er een 100 % kans om verwijderde Plating te magnetiseren aan partijleden die hen 5 % van hun maximale gezondheid als een schild dat regenereert uit de strijd. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474574] = {name = "Optellen", additional_info = "1.5 sec gegoten Reagentia: Biofuel Raket Gear [q]Party leden zijn uitgerust met Biofuel Raket Gear. Biofuel Elke vijand gedood brandstoffen de Biofuel Raket Gear verhogen Beweging Snelheid met 2 % en Haste met 2 % voor 10 sec, stapelen tot 10 keer. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474576] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Three Dimensional Bioprinter [q]Het beschadigen van een Elite schepsel onder 40 procent gezondheid creëert een onvolmaakte kopie van het op 50 % macht om te vechten aan uw zijde. Slechts 1 exemplaar kan tegelijkertijd bestaan. Het apparaat kan defect maken van onvolmaakte kopieën van uw metgezel. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474577] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Overdrive Pylon [q]Na 30 sec van de strijd, partijleden en Brann dealen 5 % meer schade en genezing voor 20 sec. Kan maar één keer per gevecht voorkomen. Je hebt deze curio al in je collectie."}
