MultiLanguageSpellData['nl'][474599] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Mechasaur EZ-Build Kit [q]Brann's Epic Egg herbergt nu 1 mechasaurs die vijanden voor (4000 / 1000) sec terwijl in het ei. Mechasaurs zal periodiek stampen in aanvulling op hun gebruikelijke capaciteiten, de handel matig Brandschade verdeeld tussen nabijgelegen vijanden. Getroffen vijanden ontploffen na 5 sec. Met matige brandschade. Brann's Epic Egg Brann roept een duivelsaurus ei op. Hopelijk komt het uit. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474600] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Automatische Footbomb Dispenser [q]Brann's spreuken en vermogens hebben de kans om 2 voetbommen op het veld te laten vallen gedurende 10 sec. Rennen in een voetbom schopt het op uw vijand doel dealen aanzienlijke brand schade aan alle vijanden in een straal van 6 yards. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474601] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Impact Conversion Matrix [q]Bij het invoeren van het gevecht activeert Brann de conversiematrix gedurende 10 sec. Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire status en splitsen tussen partij leden. Na de conversie matrix bevoegdheden naar beneden, de primaire status buff blijft gedurende 10 sec. Dit effect kan niet meer dan eenmaal per 2 minuten optreden. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474602] = {name = "Blastburn Roarcannon", additional_info = "60 yd bereik Instant [q]Flarendo volgt een doel tijdens het opladen, dan vergrendelt op zijn plaats en bereidt zich voor om te vuren. Eenmaal klaar, vuurt het een straal over de volgende 3 seconden. De straal brengt 66606435 Brand elke 0.1 sec schade aan spelers op contact, vernietigend hen."}
