MultiLanguageSpellData['nl'][474605] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Pocket Factory [q]Brann's spreuken en vaardigheden hebben de kans om de Pocket Factory opdracht te geven om 1 toren te bouwen om te helpen voor 10 sec. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474606] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Goblomagnetic Bouncing Grenade [q]Brann heeft een kans tijdens het gevecht om een GMB granaat te gooien op een vijandelijke doel omgaan met gematigde natuurschade met een 20% kans om te verdoven voor 1,5 sec. Dit heeft een kans van 25% om een nieuw doel te bereiken. De granaat kan veilig op partijleden stuiteren. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474607] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Pinged Augment Chip [q]Brann's maximale gezondheid wordt verhoogd met 4 % en zijn schade en genezing gedaan wordt verhoogd met 20 %. Tijdens het gevecht, Brann kan worden het doelwit door mechanische bots die fixeren op hem die kan worden vernietigd of verdoofd. Als ze Brann bereiken, zal hij 30 procent van zijn maximale gezondheid aan schade lijden en gedurende 5 seconden verdoofd zijn. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474608] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Reverse Engineered Goblin Death Bomb [q]Wanneer de gezondheid van een speler daalt onder 50% tijdens de strijd, Brann gooit een gigantische bom die explodeert op impact. De explosie slaat terug en vertraagt de omliggende vijanden door 45% voor 5 sec en geneest nabijgelegen partijleden voor 35% van hun maximale gezondheid. Kan alleen elke 1,5 min. voorkomen. Je hebt deze curio al in je collectie."}
