MultiLanguageSpellData['nl'][474687] = {name = "Elektro-geharged pulse", additional_info = "Instant [q]Brann's apparatuur is verbeterd met geavanceerde tech upgrades. Electro-Charged Shield Effectieve genezing gedaan aan Brann pulseert als Natuur schade aan nabijgelegen vijanden. Elektro-bekrachtigde pistool Elk schot ontladingen een elektrische stroom, boog door nabijgelegen vijanden en het verminderen van hun aanval snelheid. Brann genezen laadt zijn pistool op om meer schade aan te richten. Electro-Charged Shotgun Elke vijandelijke aanval heeft een kans om neergeslagen te worden. Brann genezen laadt zijn geweer op om meer schade aan te richten."}
