MultiLanguageSpellData['nl'][1218305] = {name = "Gesmolten hengst", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Gesmeed zoals hun schoenen ooit waren, zijn deze beesten nu minder paarden en lege energie in hun gelijkenis.\" Drop: Zone: Vision of Stormwind (Revisited)"}
MultiLanguageSpellData['nl'][1218306] = {name = "Void-Scarred Pack Moeder", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Het bestrijden van haar corrupte begeleiders deze roedel moeder bevrijdde zichzelf en haar pups. Vrijheid van hun verzorgers bevrijdde hen echter niet van de leegte in deze verloren plek. Ze leerde haar pups om nog gevaarlijker beesten te zijn, en ze stalken nu overal in Orgrimmar om haar voedsel te halen, terwijl iedereen strijdt om te overleven.\" Drop: Zone: Vision of Orgrimmar (Revisited)"}
MultiLanguageSpellData['nl'][1218307] = {name = "Void-Scarred Windrider", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Toen de lege energieën werden vrijgegeven, dreef het de meeste windrijders wild. Ze hebben elkaar en hun trainers vermoord. De poorten naar hun haan werden op slot gedaan door de overlevenden. Sommige overlevende windrijders zijn nog steeds te zien glijden boven, maar niemand durft terug te keren naar hun nieuwe dodelijke domein om te zien wat er over is.\" Drop: Zone: Vision of Orgrimmar (Revisited)"}
MultiLanguageSpellData['nl'][1218308] = {name = "Aanmaak Inferno", additional_info = "Instant [q]Blazikon ontketent een vurige uitbarsting naar elke gedoofde kaars, die kaars reinigt en 8487876 Brandschade toebrengt aan alle spelers op zijn pad. De inferno sears alle spelers, veroorzaken 242445 Brand schade elke 1 sec voor 8 sec. Dit effect stapelt zich op."}
