MultiLanguageSpellData['nl'][1218314] = {name = "Ny'alothan Schaduwworm", additional_info = "1.5 sec cast [q]Summons en ontslaat uw Ny'alothan Shadow Worm. [q]\"Een overblijfsel uit het verleden van het Zwarte Rijk, deze voorlopers van de Abyss wormen zijn opnieuw aan het oprukken met de opkomst van Ny'alotha.\" Reachement: Mastering the VisionsCategorie: Visions of N'Zoth Revisited"}
MultiLanguageSpellData['nl'][1218316] = {name = "Corruptie van de aspecten", additional_info = "1.5 sec cast [q]Summons en verwerpt de Corruptie van de Aspecten. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie. [q]\"Met N'Zoth's triomf komt wat begon met Galakrond tot bloei. Nu de Aspecten weg zijn, is de corruptie van hun soort compleet.\" Leverancier: Torie Zone: Dornogal Kosten: 40000"}
MultiLanguageSpellData['nl'][1218317] = {name = "Void-Crystal Panther", additional_info = "1.5 sec cast [q]Summons en ontslaat een berijdende Void-Crystal Panther. [q]\"Hoewel vele kostbare edelstenen zijn beschadigd door lege energieën in gruwelijke visioenen, kunnen Meester Jewelcrafters ze nog steeds gebruiken om machtige panterpaarden te vervaardigen.\" Beroep: Jewelcrafting"}
