MultiLanguageSpellData['nl'][1224959] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Ethereal Energy Converter [q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, de handel matige schade aan nabijgelegen vijanden en treiteren ze voor 4 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 20 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 2 sec. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224961] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Ethereal Energy Converter [q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, de handel matige schade aan nabijgelegen vijanden en treiteren ze voor 4 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 30 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 4 sec. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224962] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Ethereal Energy Converter [q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren ze voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 40 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 6 sec. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224963] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Ethereal Energy Converter [q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren ze voor 6 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 50 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 8 sec. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224964] = {name = "Optellen", additional_info = "1.5 sec gegoten Reagentia: Mana-Tinted Glazen [q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 4 % en schade genomen met 5 % elke 5 sec tot 10 keer. Het versturen van de bril zal Brann genezen voor 25 procent van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 2 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt onder 30 procent gezondheid die voorkomt dat de verdoving optreedt. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224965] = {name = "Optellen", additional_info = "1.5 sec gegoten Reagentia: Mana-Tinted Glazen [q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 4% en schade genomen met 5% om de 5 sec tot 10 keer. Het versturen van de bril zal Brann genezen voor 40% van zijn maximale gezondheid en verdoving nabijgelegen vijanden voor 3 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224967] = {name = "Optellen", additional_info = "1.5 sec gegoten Reagentia: Mana-Tinted Glazen [q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% elke 5 sec tot 10 keer. Het versturen van de bril zal Brann genezen voor 55% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 4 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224968] = {name = "Optellen", additional_info = "1.5 sec gegoten Reagentia: Mana-Tinted Glazen [q]Brann dons mana-tinted glazen tijdens de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% elke 5 sec tot 10 keer. Het verkopen van de bril zal Brann genezen voor 70% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 5 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1224970] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Quizzical Device [q]Brann heeft de kans om spelers een 5 % bonus te geven voor gezondheid, schade of genezing gedurende 20 sec op basis van zijn geselecteerde Combat Role. Spelers hebben een kans om Brann een 5 % bonus te geven aan gezondheid, schade, of genezing voor 20 sec. gebaseerd op hun geselecteerde rol. Je hebt deze curio al in je collectie."}
