MultiLanguageSpellData['nl'][1224978] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Hatarang [q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 1 debuff(s) toe te passen op 2 doelen. Mogelijke debuffs zijn een 20 % schade opgelopen toename, 20 % schade behandelde daling, en 20 % aanval en gegoten snelheid daling. Je hebt deze curio al in je collectie."}
