MultiLanguageSpellData['nl'][1225038] = {name = "Twilight Devastation", additional_info = "Instant Ongeveer 1 procs per minuut [q]Apply Lesser Rune of Twilight Devastation to a helm. Hiermee kunt u uw aanvallen hebben een kans om een straal van Twilight Devastation te activeren, dealen tot (1 * 845195 * 3) Schaduwschade aan vijanden voor u. Kan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2. (4s afkoeling)"}
