MultiLanguageSpellData['nl'][1225061] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Zand van K'aresh [q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, zand begint te draaien rond partijleden, het verlenen van 6 % Kritieke Strike tot 10 keer en vertragen van nabijgelegen vijanden met 6 %. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden. Je hebt deze curio al in je collectie."}
