MultiLanguageSpellData['nl'][1225064] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Zand van K'aresh [q]Wanneer Brann gebruik maakt van het verzamelen van gereedschap, zand begint te draaien rond partijleden, het verlenen van 12 % Kritieke Strike tot 10 keer en vertragen van nabijgelegen vijanden door 12 %. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225065] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Temporal Decelerator Crystal [q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of lager gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite en gegoten snelheid met 20 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 2 % stapelen Haste buff. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225066] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Temporal Decelerator Crystal [q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of lager gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite en gegoten snelheid met 30 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 4 % stapelen Haste buff. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225067] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Temporal Decelerator Crystal [q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of lager gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en gegoten snelheid met 40 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 6 % stapelen Haste buff. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225068] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Temporal Decelerator Crystal [q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of lager gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite en gegoten snelheid met 50 % gedurende 30 sec. Het doden van de doel Elite terwijl het debuff is actief verleent de partij een 8 % stapelen Haste buff. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225069] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Battered Aegis [q]Terwijl de Aegis is uitgerust, alle partijleden dealen 3 % verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 5 procent van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 1 % stapelen tot 3 keer. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225070] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Accu Aegis [q]Terwijl de Aegis is uitgerust, alle partijleden dealen 6 % verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 10 procent van de schade die je hebt opgelopen in die tijd. Wanneer een speler sterft, geeft de Aegis hen 2 procent vermindering van de schade en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 2 % stapelen tot 3 keer. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225072] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Battered Aegis [q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 9% meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 15% van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 3% vermindering van de schade en 4% verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 3% stapelen tot 3 keer. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225073] = {name = "Optellen", additional_info = "1.5 sec cast Reagentia: Battered Aegis [q]Terwijl de Aegis is uitgerust, alle partijleden dealen 12 % verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 20 procent van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen na revival, maar vermindert hun schade en genezing behandeld met 4 % stapelen tot 3 keer. Je hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225074] = {name = "Kleine Rune van Twilight Verwoesting", additional_info = "3,5 sec cast Vereist Armor [q]Apply Lesser Rune of Twilight Devastation to a helm. Hiermee kunt u uw aanvallen hebben een kans om een straal van Twilight Devastation te activeren, dealen tot (1 * 845195 * 3) Schaduwschade aan vijanden voor u. Kan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2."}
MultiLanguageSpellData['nl'][1225076] = {name = "Optellen", additional_info = "1.5 sec cast Reagents: Audio Amplification Crystal [q]Brann's stem wordt iets versterkt met Arcane magie waardoor zijn woorden de partij potentieel een buff geven op basis van wat werd gesproken. Je hebt deze curio al in je collectie."}
