MultiLanguageSpellData['nl'][1229205] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor 6% Kritische Strike tot 10 keer en vertragen nabijgelegen vijanden met 6%. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229206] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint het zand te draaien rond partijleden, waarbij 8 % Critical Strike tot 10 keer wordt toegekend en nabijgelegen vijanden met 8 % worden vertraagd. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229207] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint het zand te draaien rond partijleden, waardoor 10 % Critical Strike tot 10 keer wordt toegekend en nabijgelegen vijanden met 10 % worden vertraagd. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229208] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathing Tools gebruikt, begint zand te draaien rond partijleden, waardoor 12 % Critical Strike tot 10 keer en vertragen van nabijgelegen vijanden door 12 %. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229209] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80% of hoger en op 20% of lager gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de aanval van de Elite wordt verminderd en de snelheid van de Elite met 20% wordt gegoten gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 2% stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229210] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite en gegoten snelheid met 30 % gedurende 30 sec. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 4 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229211] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de aanval van de Elite wordt verminderd en de snelheid gedurende 30 sec met 40 % wordt gegoten. Het doden van de doel Elite terwijl de debuff is actief verleent de partij een 6 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229212] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, waardoor de aanval van de Elite en gegoten snelheid met 50 % gedurende 30 sec. Het doden van de doel Elite terwijl het debuff is actief verleent de partij een 8 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229213] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 3 procent verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 5 procent van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 1 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229214] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 6 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 10 procent van de schade die je hebt opgelopen in die tijd. Wanneer een speler sterft, geeft de Aegis hen 2 procent vermindering van de schade en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 2 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229215] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, behandelen alle partijleden 9% meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 15% van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 3% vermindering van de schade en 4% verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing behandeld met 3% stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229216] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 12 procent meer schade en genezing. Elke 10 seconden tijdens het gevecht, genezen jij en Brann voor 20 procent van de schade die je in die tijd hebt opgelopen. Wanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen na revival, maar vermindert hun schade en genezing behandeld met 4 % stapelen tot 3 keer."}
MultiLanguageSpellData['nl'][1229217] = {name = "Audio Amplification Crystal", additional_info = "[q]Brann's stem is licht versterkt met Arcane magie waardoor zijn woorden de partij mogelijk een buff geven gebaseerd op wat werd gesproken."}
