MultiLanguageSpellData['nl'][1233654] = {name = "Mana-tinted bril", additional_info = "Onbeperkt bereik Instant [q]Brann dons mana-tinted bril terwijl in de strijd, periodiek verhogen van zijn schade gedaan met 4% en schade genomen met 5% elke 5 sec tot 10 keer. Het versturen van de bril zal Brann genezen voor 40% van zijn maximale gezondheid en verdoving nabijgelegen vijanden voor 3 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
MultiLanguageSpellData['nl'][1233655] = {name = "Mana-tinted bril", additional_info = "Onbeperkt bereik Instant [q]Brann dons mana-tinted bril terwijl in de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% elke 5 sec tot 10 keer. Het versturen van de bril zal Brann genezen voor 55% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 4 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
MultiLanguageSpellData['nl'][1233656] = {name = "Mana-tinted bril", additional_info = "Onbeperkt bereik Instant [q]Brann dons mana-tinted bril terwijl in de strijd, periodiek verhogen van zijn schade gedaan met 5% en schade genomen met 5% elke 5 sec tot 10 keer. Het verkopen van de bril zal Brann genezen voor 70% van zijn maximale gezondheid en verdoven nabijgelegen vijanden voor 5 sec. Anders wordt dit effect automatisch verwijderd wanneer Brann daalt tot minder dan 30% gezondheid die voorkomt dat de verdoving optreedt."}
