MultiLanguageSpellData['nl'][1233659] = {name = "Hatarang", additional_info = "100 yd bereik Instant Ongeveer 2 procs per minuut [q]Brann heeft de kans om willekeurige hoeden uit te trekken en gooi ze naar zijn vijanden, dealen matige schade en het toepassen van 1 debuff(s) om 3 doelen. Mogelijke debuffs zijn een 25% toename van de schade, 25% vermindering van de schade en 25% daling van de aanval en gegoten snelheid. (20s afkoeling)"}
MultiLanguageSpellData['nl'][1233660] = {name = "Hatarang", additional_info = "100 yd range Instant Ongeveer 2 procs per minuut [q]Brann heeft de kans om willekeurige hoeden uit te trekken en ze naar zijn vijanden te gooien, matige schade aan te pakken en 2 debuff(s) toe te passen op 4 doelen. Mogelijke debuffs zijn een 30% toename van de schade, 30% schade behandeld daling, en 30% aanval en gegoten snelheid daling. (20s afkoeling)"}
