MultiLanguageSpellData['nl'][1233693] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik Instant [q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 8% Critical Strike tot 10 keer en vertragen nabijgelegen vijanden met 8%. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1233694] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik Instant [q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor 10% Critical Strike tot 10 keer en vertragen nabijgelegen vijanden met 10%. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1233695] = {name = "Zand van K'aresj", additional_info = "Onbeperkt bereik Instant [q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 12% Critical Strike tot 10 keer en vertragen nabijgelegen vijanden met 12%. Dealen van een kritische staking creëert een Sand Devil op de locatie van het doelwit voor 6 sec die periodiek trekt vijanden naar het centrum. Kan alleen om de 45 seconden gebeuren. Verzamelen Tools Brann maakt gebruik van zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1233699] = {name = "Ethernova", additional_info = "100 yd bereik Instant [q]Wanneer een partijlid daalt onder 60 procent gezondheid, een Ethereal Energy Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren hen voor 4 sec. Zodra de treunt verloopt, laat de Converter een Etherwave helende nabijgelegen bondgenoten vrij voor 30 procent van hun gezondheid. Kan om de 2 minuten worden geactiveerd. Het doden van vijanden vermindert de afkoeling van dit effect met 4 sec."}
