MultiLanguageSpellData['nl'][1234362] = {name = "Aanraking van Malice", additional_info = "[q]Grants 5 extra rangen van Touch of Malice. Aanraking van kwaad Uw en uw volgelingen' schadelijke spreuken en vermogens periodiek toepassen Fel Aangeraakt aan vijanden. De helse dreadlord die door Twisted Crusade werd opgeroepen, slaat altijd kritiek op Fel Touched vijanden. Fel Touched Elke 4 seconden barsten de doelwitten... en beschadigen de vijanden in de buurt... voor 3% van de schade die de laatste 4 seconden heeft veroorzaakt. Schade verminderd boven 5 doelen."}
