MultiLanguageSpellData['nl'][1235959] = {name = "Mage Spellslinger 11.2 Klasse Set 2pc", additional_info = "[q]Arcane Arcane Blast schade verhoogd met 12% en Arcane Blast verleent 1 stapel Arcane Harmony. Directe Splinter schade heeft een 25% kans om een stapel Arcane Harmony. Vuur, Frost Ice Lance en Icicle schade verhoogd met 10% en Ice Lance heeft een 50% kans om 1 stapel Cold Front te genereren. Directe Splinter schade heeft een 15% kans om een stapel Cold Front te verlenen."}
MultiLanguageSpellData['nl'][1235962] = {name = "Mage Sunfury 11.2 Klasse Set 2pc", additional_info = "[q]Arcane, Fire, Frost Spellfire Sphere spreuk bonus verhoogd met 1,0%. Mana Cascade verleent nu een extra 0,5% Haste per stack."}
MultiLanguageSpellData['nl'][1235963] = {name = "Mage Frostfire 11.2 Klasse Set 2pc", additional_info = "[q]Fire Comet Storm en Frostfire Burst schade verhoogd met 15%. Frostfire Bolt schade steeg met 8%. Comet Storm, Frostfire Burst en Frostfire Bolt passen Ignite nu toe op 75% effectiviteit. Arcane, Frost Meteor en Frostfire Burst schade steeg met 30%. Frostfire Bolt schade steeg met 10%. Meteor, Frostfire Burst en Frostfire Bolt passen nu Ignite toe, waarbij 25% extra schade over 9 sec."}
MultiLanguageSpellData['nl'][1235964] = {name = "Mage Spellslinger 11.2 Klasse Set 4pc", additional_info = "[q]Arcane Splinterschade nam toe met 8%. Arcane Orb heeft een 100% kans om een stapel Arcane Harmony toe te kennen, tot 8 keer. Bij het bereiken van 20 stapels Arcane Harmony, krijgen Intuïtie op 100% effectiviteit. Brand Splinterschade nam toe met 8%. Arcane Orb heeft een 100% kans om een stapel Arcane Harmony toe te kennen, tot 8 keer. Wanneer Cold Front een bevroren bol oproept, verhoog je spreuk schade met 8% voor 10 sec. Frost Wanneer Frozen Orb deals schade aan een of meer vijanden, het heeft een 15% kans om een stapel Cold Front. Wanneer Cold Front een bevroren bol oproept, verhoog je spreuk schade met 8% voor 10 sec. (100ms afkoeling)"}
MultiLanguageSpellData['nl'][1235965] = {name = "Mage Sunfury 11.2 Klasse Set 4pc", additional_info = "[q]Fire, Frost Uitzonderlijke spreuken van uw Phoenix voegt een extra 0.3 sec toe aan de duur van uw volgende Hyperthermie. Wanneer uw Phoenix verloopt, geeft het u nog meer kracht, waardoor de Minder Tijd Warp en 10% verhoogde spreukschade gedurende 10 sec. Arcane Uitzonderlijke spreuken van uw Phoenix voegt een extra 0,5 sec toe aan de duur van uw volgende Arcane Ziel. Als je Phoenix afloopt, geeft het je nog meer kracht... en geeft het Lesser Time Warp en 20% verhoogde spreukschade gedurende 10 sec."}
MultiLanguageSpellData['nl'][1235966] = {name = "Mage Frostfire 11.2 Klasse Set 4pc", additional_info = "[q]Arcane, Frost Casting Glacial Spike heeft een 100% kans om ook een Pyroblast te werpen, dealer (352.5% van Spell Power) Brandschade. Daarnaast profiteert Pyroblast nu van Ignite. Fire Casting Pyroblast heeft een 20% kans om ook een Glacial Spike dealer (366,24% van Spell Power) Frost schade. Glacial Spikes cast op deze manier niet wortelen. Daarnaast profiteert Glacial Spike nu van Ignite."}
MultiLanguageSpellData['nl'][1235967] = {name = "Void Lure", additional_info = "25 yd bereik 1 sec gegoten [q]Gooi de leegte lokaas op de stapel etherische resten om Ramon'ta aan te trekken."}
MultiLanguageSpellData['nl'][1235973] = {name = "Wraakzuchtige Leegte Barrier", additional_info = "Instant [q]Het nemen van schade infurieert u, waardoor u te absorberen 202 schade en deal 461 Schaduwschade per infuriatie splitsen tussen nabijgelegen vijanden. De schade steeg met 30% per extra vijand, tot 150%. U kunt elke 15 sec verder woedend, stapelen tot 15 keer, maar kalmeer snel bij het verlaten van de strijd. Alleen geldig voor tankspecialisaties."}
