MultiLanguageSpellData['nl'][1236330] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 4pc", additional_info = "[q]Feral Ravage heeft een kans van 40% om je weer je doel te laten verpesten 4 sec later op 100% van de aanvankelijke kracht. Balance, Guardian, Restauratie Ravage heeft een 40% kans om je je doel opnieuw te vernietigen 4 sec later met 60% effectiviteit."}
MultiLanguageSpellData['nl'][1236331] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 2pc", additional_info = "[q]Ravage verhoogt uw haast met 10%, de kans om kritisch toe te slaan met 10%, en de schade uw bloedingen omgaan met 30% voor 5 sec. (100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236332] = {name = "Druid Elune's gekozen 11.2 klasseset 2pc", additional_info = "[q]Balance Starfire schade verhoogd met 15%. Het verkrijgen van Astral Power met Starfire heeft een 40% kans om een Starsurge te lanceren op een slachtoffer met 45% effectiviteit. Feral, Guardian, Restauratie De schade is met 20% toegenomen. Thrash heeft 40% kans om een Starsurge te lanceren op een slachtoffer met 160% effectiviteit. (100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236333] = {name = "Druid Elune's gekozen 11.2 klasse Set 4pc", additional_info = "[q]Balance On impact, Starsurges gelanceerd door Starfire splitsen tot maximaal 3 extra doelen op 40% effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Furie van Elune of Volle Maan verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec. Feral, Guardian, Restauratie Op impact, Starsurges gelanceerd door Thrash splitsen tot maximaal 3 extra doelen op 20% effectiviteit en verlenen een stapel van Gathering Moonlight. Afgietsel Maanstraal verbruikt Verzamelen Maanlicht om uw schade te verhogen met 4% per stack voor 12 sec."}
MultiLanguageSpellData['nl'][1236334] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 2pc", additional_info = "[q]Balance, Feral, Guardian Casting Hemelse Uitlijning roept de hulp van een dryad voor 10 sec die werpt Starsurge op 360% effectiviteit en Starfall op 800% effectiviteit. Herstel Casting Incarnation: Boom van het Leven of Convoceer de Geesten roept de hulp van een droogtrommel voor 5 sec die Tranquility werpt op 50% effectiviteit en onmiddellijk hergroeit uw laagste gezondheid bondgenoot met 200% effectiviteit."}
MultiLanguageSpellData['nl'][1236336] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 4pc", additional_info = "[q]Balance, Feral, Guardian Wanneer uw Dryad vervaagt, uw volgende 2 Starsurges schade voor een extra bedrag gelijk aan 3% van uw schade gedaan terwijl het actief was en spatten 10% van hun schade op nabijgelegen vijanden, verminderd meer dan 5 doelen. Herstel Wanneer uw Dryad vervaagt, geneest uw volgende 2 Swiftmends voor een extra bedrag gelijk aan 5% van uw genezing gedaan terwijl het actief was en spettert 25% van hun genezing op nabijgelegen bondgenoten, gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236337] = {name = "Druid Wildstalker 11.2 Klasse Set 2pc", additional_info = "[q]Feral De snelheid waarmee Bloodseeker Vines groeien wordt met 40% verhoogd. Tiger's Fury zorgt ervoor dat Bloodseeker Vines groeien op maximaal 3 geldige nabijgelegen vijanden. Balance, Guardian, Restauratie De snelheid waarmee Symbiotic Blooms groeien wordt verhoogd met 45%. Gieten Hergroei met Clearcasting zorgt ervoor dat Symbiotic Blooms groeien op maximaal 2 geldige nabijgelegen bondgenoten."}
MultiLanguageSpellData['nl'][1236338] = {name = "Druid Wildstalker 11.2 Klasse Set 4pc", additional_info = "[q]Feral Bloodseeker Vines hebben een 20% kans om Bursting Growth elke 2 sec op 100% effectiviteit te activeren. Elke stapel Bloodseeker Vines op een vijand verhoogt Bursting Groei schade genomen met 40%. Balance, Guardian, Restoration Symbiotic Blooms hebben een 35% kans om Bursting Growth elke 2 sec op 100% effectiviteit te activeren. Elke stapel van Symbiotic Blooms op een bondgenoot verhoogt Bursting Groei genezing genomen met 30%."}
MultiLanguageSpellData['nl'][1236342] = {name = "Voorbereiden van staking", additional_info = "Instant [q]Feral Ravage heeft een kans van 40% om je je doel opnieuw te vernietigen 4 sec later op 100% van de aanvankelijke kracht. Balance, Guardian, Restauratie Ravage heeft een 40% kans om je je doel opnieuw te vernietigen 4 sec later met 60% effectiviteit."}
