MultiLanguageSpellData['nl'][1236354] = {name = "Soul Siphon", additional_info = "40 yd bereik {2 sec cast} {5 sec cooldown} [q]Caster vertraagt hun doel en draineert 622547 gezondheid over 8 sec, genezing van de caster voor twee keer de hoeveelheid drainage."}
MultiLanguageSpellData['nl'][1236355] = {name = "Death Knight Rijder van de Apocalyps 11.2 Klasseset 2pc", additional_info = "[q]Blood, Unholy Apocalypse roept nu Whitemane voor 10 sec. Whitemane's Undeath dealt 20% meer schade en infecteert 1 extra doel als het zich verspreidt, en haar Death Coil dealt 35% meer schade. Frost Pillar of Frost roept nu Trollbane voor 10 sec. Trollbane's Icy Fury dealt 20% meer schade... en zijn obliterate dealt 15% meer schade."}
MultiLanguageSpellData['nl'][1236356] = {name = "Death Knight Rider van de Apocalyps 11.2 Klasse Set 4pc", additional_info = "[q]Blood, Unholy Casting Death Coil of Epidemic beveelt Whitemane om haar Death Coil of Epidemic naast je te werpen met 125% effectiviteit. Jouw doodsoorzaak is 40% meer schade aan doelwitten dan Whitemane's dood. Frost Casting Obliterate of Frostscyde beveelt Trollbane om zijn Obliterate of Frostscythe samen met u te werpen op 100% effectiviteit. Jouw obliterate dealt 20% meer schade aan doelen beïnvloed door Trollbane's Icy Fury. (500m afkoeling)"}
MultiLanguageSpellData['nl'][1236358] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasseset 2pc", additional_info = "[q]Reaver's Glaive schade wordt verhoogd met 50% en andere fysieke schade wordt verhoogd met 25%."}
MultiLanguageSpellData['nl'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasse Set 4pc", additional_info = "[q]Havoc Fury van de Aldrachi geeft Blade Dance nog meer kracht na Chaos Strike, waardoor het aantal slashes toeneemt tot 12. Reaver's Mark stapelt nu tot 2 keer en versterkt verder Chaos Strike wanneer gegoten na Blade Dance, het toepassen van een extra stack voor 100% van de normale duur. Wraak Fury van de Aldrachi versterkt verder Ziel Cleave wanneer gegoten na Shear, toenemende slashes tot 12. Reaver's Mark stapelt nu tot 2 keer en versterkt Shear wanneer gegoten na Soul Cleave, het toepassen van een extra stack voor 100% van de normale duur."}
MultiLanguageSpellData['nl'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Klasseset 2pc", additional_info = "[q]Havoc Immolation Aura behandelt 30% verhoogde schade en verhoogt Chaos Strike schade met 20% terwijl actief. Wraak Immolation Aura behandelt 30% verhoogde schade en verhoogt de Soul Cleave schade met 20% terwijl ze actief is."}
MultiLanguageSpellData['nl'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Klasse Set 4pc", additional_info = "[q]Havoc Het betreden van demonische vorm leidt nu onmiddellijk tot een Demonsurge en verbrijzelt een demon ziel fragment dat 20% verhoogde schade voor 10 sec. Wraak Het betreden van demonenvorm leidt nu onmiddellijk tot een Demonsurge en verbrijzelt een demonenzielfragment dat 20% verhoogde schade geeft gedurende 15 sec. (100ms afkoeling)"}
MultiLanguageSpellData['nl'][1236364] = {name = "Evoker Flameshaper 11.2 Klasseset 2pc", additional_info = "[q]Devastation Engulf stokt uw Innerlijke Vlam, het verhogen van uw schade en genezing na verloop van tijd met 15% en het verhogen van uw kans om Essence Burst te krijgen met 50% voor 12 sec. Stacks tot 2 keer. Meerdere aanvragen kunnen elkaar overlappen. Behoud, Augmentation Engulf stokt uw Innerlijke Vlam, het verhogen van uw schade en genezing in de tijd met 25% en het verhogen van uw kans om Essence Burst te krijgen met 50% voor 12 sec. Stacks tot 2 keer. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236365] = {name = "Evoker Flameshaper 11.2 Klasse Set 4pc", additional_info = "[q]Vernietiging Verzadigen Essence Burst tijdens Inner Flame vuurt een Essence Bomb op uw doel, schadelijke nabijgelegen vijanden voor (371% van de Spell Power) Arcane, gereduceerd tot meer dan 5 doelen. Behoud, Augmentation Consuming Essence Burst tijdens Inner Flame vuurt een Essence Bomb op uw doel, helende nabijgelegen bondgenoten voor (250% van Spell Power), gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236366] = {name = "Evoker Schaalcommander 11.2 Klasseset 2pc", additional_info = "[q]Augmentatie Tijdens het vliegen tijdens Deep Breath en gedurende 20 seconden daarna, voer je een eskader van 2 Dracthyr uit die je doelwitten zal aanvallen met Disintegrate en Pyre. Verwoesting, Bewaring Tijdens het vliegen tijdens Deep Breath en voor 10 seconden na, je commando een squadron van 2 Dracthyr die uw doelen zal aanvallen met Disintegrate en Pyre."}
MultiLanguageSpellData['nl'][1236367] = {name = "Evoker Scalecommander 11.2 Klasse Set 4pc", additional_info = "[q]Vernietiging Terwijl uw eskader actief is, slaat uw Mass Disintegrate tot 2 extra doelen. Bovendien helpt je eskader je nog 5 seconden. Augmentatie Terwijl je eskader actief is, komt je massale uitbarsting tot twee extra doelen. Bovendien helpt je eskader je nog 10 seconden. Behoud Terwijl uw eskader actief is, uw Mass Eruption slaat tot twee extra doelen. Bovendien helpt je eskader je nog 5 seconden."}
MultiLanguageSpellData['nl'][1236368] = {name = "Evoker Chronowarden 11.2 Klasseset 2pc", additional_info = "[q]Tip de afkoeling van de Scales wordt verminderd met 60 sec."}
MultiLanguageSpellData['nl'][1236369] = {name = "Evoker Chronowarden 11.2 Klasse Set 4pc", additional_info = "[q]Temporal Burst zorgt ervoor dat Chrono Flames 2 extra doelen aanvallen en herhalen 15% extra schade of genezing, tot een maximum van [(Spell Power * 4.5) * (1 + Versatility)], en verhoogt Essence vermogen schade en genezing met 30%."}
MultiLanguageSpellData['nl'][1236370] = {name = "Hunter Dark Ranger 11.2 Klasse Set 2pc", additional_info = "[q]Beast Mastery Black Arrow pijlschade steeg met 10% en Bleak Powder schade steeg met 20%. De afkoeling van Call of the Wild wordt verminderd met 60 sec. Marksmanship, Survival Black Arrow pijlschade verhoogd met 10% en Bleak Powder schade verhoogd met 20%. De afkoeling van Trueshot wordt verminderd met 30 sec."}
MultiLanguageSpellData['nl'][1236371] = {name = "Hunter Dark Ranger 11.2 Klasse Set 4pc", additional_info = "[q]Beast Mastery, Marksmanship, Survival Withering Fire's Black Arrow schade steeg met 50%. Consuming Deathblow heeft een 50% kans om alle Black Arrow barrages tijdens uw volgende Withering Fire te vuren 1 extra Black Arrow."}
MultiLanguageSpellData['nl'][1236372] = {name = "Hunter Pack Leader 11.2 Klasse Set 2pc", additional_info = "[q]Marksmanschap, Survival Pet schade steeg met 15% en Beast schade steeg met 15%. Het oproepen van een Beest verleent 6% haast, meesterschap, of kritische aanval kans op basis van het Beest opgeroepen voor 8 sec. Beast Mastery Pet schade steeg met 5% en Beast schade steeg met 15%. Het oproepen van een Beest verleent 6% haast, meesterschap, of kritische aanval kans op basis van het Beest opgeroepen voor 8 sec."}
MultiLanguageSpellData['nl'][1236373] = {name = "Hunter Pack Leader 11.2 Klasse Set 4pc", additional_info = "[q]Summoning a Beast terwijl onder de effecten van Lead from the Front de nabijgelegen wilde dieren in een Stampede, opladen van uw doel en dealen [(300% of Attack Power) * 9] Fysieke schade tot maximaal 8 vijanden over 7 sec."}
MultiLanguageSpellData['nl'][1236374] = {name = "Hunter Sentinel 11.2 Klasse Set 2pc", additional_info = "[q]Het merk Rapid Fire is met 25% toegenomen. Wanneer Maanstorm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Aimed Shots om Arcane schade aan te pakken en hun schade verhoogd met 10%. Beast Mastery, Survival Wildfire Bom schade verhoogd met 10%. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Wildfire Bombs om Arcane schade aan te pakken en hun initiële schade verhoogd met 150%."}
MultiLanguageSpellData['nl'][1236375] = {name = "Hunter Sentinel 11.2 Klasse Set 4pc", additional_info = "[q]De schade van Markmanship Sentinel wordt met 18% verhoogd. De Boon van Elune is nu actief voor de duur van Maanstorm met 100% effectiviteit. Beast Mastery, de schade van Survival Sentinel is verhoogd met 20%. De Boon van Elune is nu actief voor de duur van Maanstorm met 100% effectiviteit."}
