MultiLanguageSpellData['nl'][1236377] = {name = "Monk Master of Harmony 11.2 Klasse Set 2pc", additional_info = "[q]Brewmaster Het verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge te ontketenen, dealen [180 * (400% of Spell Power) / 100] Natuurschade verdeeld tussen uw doel en andere nabijgelegen vijanden, en [20 * (500% of Spell Power) / 100] genezing tot maximaal 5 gewonde bondgenoten. Windwalker, Mistweaver Het verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge te ontketenen, dealen [20 * (400% of Spell Power) / 100] Natuurschade verdeeld tussen uw doel en andere nabijgelegen vijanden, en [90 * (500% of Spell Power) / 100] genezing tot maximaal 5 gewonde bondgenoten."}
MultiLanguageSpellData['nl'][1236378] = {name = "Monkmeester van Harmonie 11.2 Klasse Set 4pc", additional_info = "[q]Windwalker, Mistweaver Casting Thunder Focus Tea garandeert dat uw volgende 2 casts van Tiger Palm een Harmonic Surge zal veroorzaken. Brewmaster Casting garandeert dat uw volgende 2 casts van Tiger Palm een Harmonic Surge zal activeren."}
MultiLanguageSpellData['nl'][1236379] = {name = "Monk Shado-Pan 11.2 Klasseset 2pc", additional_info = "[q]Brewmaster Flury Strikes deal 10% meer schade en het activeren van Wapens of Order direct verleent 10 stapels van Flury Strikes die leiden tot uw volgende aanval op 70% effectiviteit. Windwalker, Mistweaver Flury Strikes deal 20% meer schade en het activeren van Storm, Aarde, en Vuur onmiddellijk verleent 10 stapels van Flury Strikes die trigger op uw volgende aanval met 70% effectiviteit."}
MultiLanguageSpellData['nl'][1236380] = {name = "Monk Shado-Pan 11.2 Klasse Set 4pc", additional_info = "[q]Brewmaster De ladingsgeneratie van Vloeistoffen wordt met 30% verhoogd en Flury Strikes activeert elke 150 energie die tijdens Wapens van Orde wordt verbruikt. Windwalker Flury lading generatie wordt verhoogd met 50% en Flury Strikes triggers elke 120 energie besteed tijdens Storm, Aarde en Vuur. Mistweaver De ladingsproductie van Vloeistof wordt met 50% verhoogd en Flury Strikes activeert elke 150 energie besteed tijdens Wapens van Orde."}
MultiLanguageSpellData['nl'][1236381] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 2pc", additional_info = "[q]Windwalker Heart of the Jade Serpent extra triggers voor 4 sec op 100% effectiviteit na het werpen van Slicing Winds. Brewmaster, Mistweaver Heart of the Jade Serpent activeert bovendien 8 sec op 100% effectiviteit nadat je Thunder Focus Tea hebt gegoten. (1s afkoeling)"}
MultiLanguageSpellData['nl'][1236382] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 4pc", additional_info = "[q]Hart van de Jade Slang verhoogt uw haast met 10% terwijl u actief bent en 4 sec daarna."}
MultiLanguageSpellData['nl'][1236383] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 2pc", additional_info = "[q]Retributie De genezing en schade van Dawnlight wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra [10][10] sec. Bescherming Dawnlight's genezing en schade wordt verhoogd met 30% en je krijgt Solar Wrath na Wraak vervaagt waardoor Sun's Avatar effect blijft hangen voor een extra [10][10] sec. Holy (Avenging Wrath) Dawnlight's genezing en schade wordt verhoogd met 60% en je krijgt Solar Wrath na Avenging Wrath vervaagt waardoor het effect van Sun's Avatar blijft hangen voor een extra 10[10][10] sec."}
MultiLanguageSpellData['nl'][1236384] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 4pc", additional_info = "[q]Retributie Zonne Wrath verhoogt de effectiviteit van uw Heilige Kracht uitgavenders met 15% en verleent u [2][2] Dawnlight. Bescherming Zonne Wrath verhoogt de effectiviteit van uw Holy Power uitgavenders met 15% en verleent u [2][2] Dawnlight. Holy (Avenging Wrath) Solar Wrath verhoogt de effectiviteit van uw Holy Power uitgavenders met 30% en verleent u 2[2][2] Dawnlight."}
