MultiLanguageSpellData['nl'][1236389] = {name = "Paladin Lightsmith 11.2 Klasse Set 2pc", additional_info = "[q]Protection Hammer en Anvil's schade wordt verhoogd met 15% en het kan ook worden geactiveerd met 40% effectiviteit. Retribution Hammer en Anvil's genezing wordt verhoogd met 15% en het kan ook worden geactiveerd door Crusader Strike op 40% effectiviteit. Holy Hammer en Anvil's genezing wordt verhoogd met 15% en het kan ook worden geactiveerd door Crusader Strike met 75% effectiviteit. (750m afkoeling)"}
MultiLanguageSpellData['nl'][1236390] = {name = "Paladin Lightsmith 11.2 Klasse Set 4pc", additional_info = "[q]Hammer en Anvil verlenen ook een stapel meesterwerk, waardoor uw volgende Heilige Bewapening een kleinere versie van zichzelf op een nabijgelegen bondgenoot voor elke stack werpen."}
MultiLanguageSpellData['nl'][1236391] = {name = "Paladin Templar 11.2 Klasse Set 2pc", additional_info = "[q]Uw Empyrean Hammer deals 20% verhoogde kritieke stakingsschade en de kritische stakingen hebben 50% kans om een extra stapel van Light's Deliverance te verlenen. (Probleem: 50%)"}
MultiLanguageSpellData['nl'][1236392] = {name = "Paladin Tempeliers 11,2 Klasse Set 4pc", additional_info = "[q]Holy, Protection Hammer of Light deals 35% verhoogde schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 keer na Eye of Tyr. Retribution Hammer of Light deals 35% verhoogde schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 keer na Wake of Ashes."}
MultiLanguageSpellData['nl'][1236394] = {name = "Priester Oracle 11.2 Klasse Set 2pc", additional_info = "[q]Holy, Shadow Casting Prayer of Mending geneest uw doel voor (1400% van Spell Power). Discipline De eerste bout van elke Penance cast schade of genezing voor 200% meer."}
MultiLanguageSpellData['nl'][1236395] = {name = "Priester Oracle 11.2 Klasse Set 4pc", additional_info = "[q]Casting Premonition of Fiety or Premonition of Solace verleent 2 stapels voorgevoel van Insight op 100% effectiviteit. Het consumeren van een stapel van Voorgevoel van Insight verhoogt uw Haste met 1,0% voor 10 sec. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236396] = {name = "Priester Voidweaver 11.2 Klasseset 2pc", additional_info = "[q]Discipline Void Blast en Penance schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%. Holy Void Blast schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%. Schaduw Void Blast schade wordt verhoogd met 30% en Void Blast's gegoten tijd wordt verminderd met 20%. De afkoeling van Void Blast is met 50% verminderd."}
MultiLanguageSpellData['nl'][1236397] = {name = "Priester Voidweaver 11.2 Klasse Set 4pc", additional_info = "[q]Discipline Void Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Void verhoogt Entropic Rift's schade met nog eens 10%, en de schade van je volgende Mind Blast wordt verhoogd met maximaal 300% op basis van de grootte van Entropic Rift wanneer het instort. Holy Void Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Void verhoogt Entropic Rift's schade met 10%, en de schade van uw volgende Void Torrent wordt verhoogd met maximaal 200% op basis van de grootte van Entropic Rift wanneer het instort. Shadow Void Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Void verhoogt Entropic Rift's schade met nog eens 10%, en de schade van uw volgende Void Torrent wordt verhoogd met maximaal 60% op basis van de grootte van Entropic Rift wanneer het instort."}
MultiLanguageSpellData['nl'][1236398] = {name = "Priester Archon 11.2 Klasse Set 2pc", additional_info = "[q]Shadow Halos genereren een extra 10 krankzinnigheid over 5 sec en Resonant Energy verhoogt bovendien de schade van uw Devouring Plague met 5,0%. Discipline, Heilige Halos verminderen de afkoeling van uw Heilige Woord: Sereniteit en Heilig Woord: Sanctificeren met 5 sec en Resonante Energie verhoogt bovendien de genezing van uw Heilige Woorden met 5,0%."}
MultiLanguageSpellData['nl'][1236399] = {name = "Priester Archon 11.2 Klasse Set 4pc", additional_info = "[q]Discipline, Shadow Terwijl Power Surge is actief, elke 2 casts van Devouring Plague voegt een andere Halo aan het effect op 100% effectiviteit, tot 2 keer. Holy While Power Surge is actief, elke 2 casts van Heilig Woord: Sereniteit of Heilig Woord: Sancitify voegt een andere Halo toe aan het effect op 100% effectiviteit, tot 2 keer."}
MultiLanguageSpellData['nl'][1236400] = {name = "Rogue Deathstalker 11.2 Klasse Set 2pc", additional_info = "[q]Assassination Shiv verhoogt de effectiviteit van alle Deathstalker schade-effecten en schade bonussen met 60% terwijl actief. Outlaw, Subtiliteit Symbolen van Dood verhoogt de effectiviteit van alle Deathstalker schade effecten en schade bonussen met 40% terwijl actief."}
MultiLanguageSpellData['nl'][1236401] = {name = "Rogue Deathstalker 11.2 Klasse Set 4pc", additional_info = "[q]Assassinatie Shiv heeft 3 sec langere duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd. Outlaw, Subtiliteit Symbolen van de Dood heeft 3 sec verlengd duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd."}
MultiLanguageSpellData['nl'][1236402] = {name = "Rogue Fatebound 11.2 Klasse Set 2pc", additional_info = "[q]Outlaw Ghostly Strike dealt 50% verhoogde schade en heeft 4 sec langere duur. Edge Case draait nu een extra Fatebound Coin en activeert Ghostly Strike activeert het effect. Vermoording, Subtlety Kingsbane handelt 10% verhoogde schade en heeft 4 sec langere duur. Edge Case draait nu een extra Fatebound Coin en activeert Kingsbane activeert zijn effect."}
MultiLanguageSpellData['nl'][1236403] = {name = "Rogue Fatebound 11.2 Klasse Set 4pc", additional_info = "[q]Outlaw Met een gelukkige Fatebound Coin vermindert de afkoeling van Adrenaline Rush met 30.0 sec en Ghostly Strike met 15.0 sec. Assassination, Subtlety Having a lucky Fatebound Coin reduceert de afkoeling van Deathmark met 30.0 sec en Kingsbane met 15.0 sec."}
MultiLanguageSpellData['nl'][1236404] = {name = "Rogue Trickster 11.2 Klasse Set 2pc", additional_info = "[q]Unseen Blade dealt 35% verhoogde schade en heeft een 35% kans om twee keer toe te slaan."}
