MultiLanguageSpellData['nl'][1245357] = {name = "Adorned Northeron Gryphon", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De oudere gryphon renners en hoge sjamanen van de Northeron Wildhammer sierden vaak hun gryfons in sierlijke, met veer bedekte stukken, wat hun rang en status aangeeft.\" Trading Post"}
MultiLanguageSpellData['nl'][1245358] = {name = "High Shaman's Aerie Gryphon", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De oude Wildhammer sjamanen die voor het eerst gryphons tegenkwamen geloofden dat ze elementaire geesten in sterfelijke vorm. Deze ontmoeting zou voor eeuwig indrukken op de Wildhammer clan voor de komende generaties.\""}
MultiLanguageSpellData['nl'][1245359] = {name = "Cinder-Plumed Highland Gryphon", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Volgens Wildhammer legende, het oranje verenkleed gevonden op gryphons wordt verondersteld een erfelijke eigenschap doorgegeven uit hun elementaire voorouders.\" Trading Post"}
