MultiLanguageSpellData['nl'][1245361] = {name = "Emberwing Sky Guide", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Vanuit de uitlopers van Khaz Modan, volgden we zijn door de zon verlichte vleugels - een in het noorden gebonden fakkel over de donkere zomerhemel.\" - De Pelgrimage van de Eerste Wildsage Trading Post"}
MultiLanguageSpellData['nl'][1245370] = {name = "Ornery Breezestider", additional_info = "1.5 sec cast [q]Summons en ontslaat uw Ornery Breezestrider. [q]\"Deze talbuk is een koppige, koppige berg, zelfs na het leren kennen van zijn ruiter. Rijders pas op.\" Trading Post"}
MultiLanguageSpellData['nl'][1245376] = {name = "Arcane Hunter", additional_info = "Instant [q]Uw schadelijke spreuken en gevarieerde vaardigheden kritische stakingen hebben een hoge kans om u Arcane Hunter tot 5 keer, het verhogen van uw Critical Strike rating met 14 per stack voor 8 sec."}
MultiLanguageSpellData['nl'][1245377] = {name = "Verhuizers inschakelen", additional_info = "Instant [q]So'azmi zet paren van Relocators in om zijn vijanden te verwarren. Wanneer een speler een Relocator aanraakt, worden ze onmiddellijk geteleporteerd naar de andere Relocator die er mee overeenkomt."}
