MultiLanguageSpellData['nl'][1248053] = {name = "Twilight Reflections", additional_info = "100 yd bereik 3 sec cast [q]Eternus roept alternatieve kwaadaardige partijleden op. Eternus roept kwaadaardige tijdlijnversies op van spelers die proberen essentie te stelen. Als ze hun doel bereiken, werpen ze gestolen Essence, verminderen maximale gezondheid, schade en genezing gedaan met 6 % gedurende 30 sec. De onstabiele kopieën zijn voortdurend Unrravelling, lijden 5% maximale gezondheid als Arcane schade elke 1 sec. Na de dood wierpen ze in plaats daarvan Merged Essence en gaven hun doel verhoogde maximale gezondheid, schade en genezing gedaan met 30% voor 20 sec."}
