MultiLanguageSpellData['nl'][1249462] = {name = "Deal: Kartel Zo", additional_info = "Instant [q]Maak een deal met Kartel Zo die je het recht geeft om jezelf een van hen te noemen (voor een week). Oorlogsband Contract Je mag maar een deal sluiten met één Kartel per week. Dit effect wordt gedeeld over uw Warband."}
