MultiLanguageSpellData['nl'][1249464] = {name = "Boon van Elune", additional_info = "Instant [q]Marksmanship Rapid Fire schade verhoogd met 25%. Wanneer Maanstorm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Aimed Shots om Arcane schade aan te pakken en hun schade verhoogd met 10%. Beast Mastery, Survival Wildfire Bom schade verhoogd met 10%. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Wildfire Bombs om Arcane schade aan te pakken en hun initiële schade verhoogd met 150%."}
