MultiLanguageSpellData['nl'][1250285] = {name = "Haaitest Crest-Horn", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De Crest-Horn zal vaak worden aangetrokken om te grazen op de planten die groeien in de zee. Sommigen hebben dapper de felste wilde dieren daar, waardoor ze echte Kalu'ak.\" Trading Post"}
MultiLanguageSpellData['nl'][1250287] = {name = "Floestrider Crest-Horn", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De zelden geziene inheemse van de Azure Span wordt beschouwd als gezegend door de slagtand van de regio.\" Trading Post"}
MultiLanguageSpellData['nl'][1250288] = {name = "Cragstepper Crest-Horn", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Tuskaar worden niet vaak gevonden op Highmountain, maar de kamhoorns komen vaak naar de kust om zeldzame lekkernijen te zoeken in de kustwateren.\" Trading Post"}
MultiLanguageSpellData['nl'][1250314] = {name = "Phantom Bloom", additional_info = "5 yd bereik 2,5 sec gegoten [q]Phantom Bloom zijn de energie overblijfselen van inheemse K'areshi flora, onmogelijk te integreren in Algari recepten. In plaats daarvan kunt u Phantom Bloom uitwisselen op de Resource Market for Algari materialen. Hun prijzen veranderen elke dag, dus geduld kan u helpen de beste deals!"}
MultiLanguageSpellData['nl'][1250317] = {name = "Lush Phantom Bloom", additional_info = "5 yd bereik 2,5 sec gegoten [q]Phantom Bloom zijn de energie overblijfselen van inheemse K'areshi flora, onmogelijk te integreren in Algari recepten. In plaats daarvan kunt u Phantom Bloom uitwisselen op de Resource Market for Algari materialen. Hun prijzen veranderen elke dag, dus geduld kan u helpen de beste deals! Enkele voorbeelden van Phantom Bloom zijn duidelijk groter dan verwacht. Ooit een van de weinige planten om de genadeloze afval van de K'aresh woestijnen te overleven, het was bekend om te gedijen in grotere rassen in de weelderige omgeving van de ongetemde bossen."}
