MultiLanguageSpellData['nl'][1250879] = {name = "Leystone Basilisk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Deze prachtige basilisk wordt vaak gejaagd op de magische eigenschappen van zijn organen. Gelukkig voor de basilisk, de verbinding met leylijnen geeft het een voorwetenschap van het naderen van roofdieren.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1250880] = {name = "Felslate Basilisk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Eenmaal gebruikelijk op de Broken Eilanden, felslate basilisks zijn zwaar gejaagd door mijnwerkers op zoek naar hun kostbare huiden.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1250881] = {name = "Aquamarine Basilisk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Ondanks hun naam, aquamarijn basilisken feesten op een verscheidenheid van kustkristallen en oceanische rotsen.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1250882] = {name = "Illidari Dreadstalker", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Ondanks hun smaak voor vlees en onnatuurlijk vermogen om angst te ruiken, zijn deze mindere demonen gedomineerd door de Illidari zoals men een jachtgezel zou temmen.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1250884] = {name = "Illidari Blightstalker", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Deze demonen verslinden pest en genieten in verval. Wie dacht dat het een goed idee zou zijn om ze te berijden?\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1250886] = {name = "Highland Elderhorn", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De huid van een hoogland vlierhoorn is ongelooflijk dik. Nooit in de geregistreerde geschiedenis heeft een hoogland vlierhoorn zelfs knipperde in reactie op beledigingen gegooid op hen.\" World Event: WoW Remix: Legion"}
