MultiLanguageSpellData['nl'][1251255] = {name = "Treetop Highmountain Eagle", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De majestueuze adelaar is een symbool van trots voor de hoge bergstammen. Het vermogen van dit grote beest om tauren op hun rug te dragen spreekt tot de pure kracht en grootte van de schepselen van Highmountain.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251257] = {name = "Leyfrost Manasaber", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount."}
MultiLanguageSpellData['nl'][1251259] = {name = "Toevoegen Keystone Affix: Tyrannisch versterkt", additional_info = "Instant [q]Voeg het Tyrannisch versterkte affix toe aan een Mythische Keystone."}
MultiLanguageSpellData['nl'][1251264] = {name = "Nightwell Manasaber", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount."}
MultiLanguageSpellData['nl'][1251265] = {name = "Arcberry Manasaber", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Genoemd naar hun gelijkenis met de heldere bessen gemaakt in arckine, deze trotse katten hebben een scherp bewustzijn van de leylijnen die onder hen.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251266] = {name = "Droombolt", additional_info = "30 yd range {2 sec cast} {3 sec cooldown} [q]Hurl earth at an vijand dealing 150 Fysieke schade."}
MultiLanguageSpellData['nl'][1251279] = {name = "Fel-Scarred Mana Ray", additional_info = "1.5 sec cast [q]Summons en ontslaat een Fel-Scarred Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie. [q]\"Overleven op Argus is geen gemakkelijke taak. Zijn leerachtige huid littekens door fel corruptie, deze mana straal is gevoelig voor aanvallen, meer dan gebruikelijk.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251281] = {name = "Bloodtooth Mana Ray", additional_info = "1.5 sec cast [q]Summons en ontslaat een Bloodtooth Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie. [q]\"De verbrijzeling van Argus dreef dit ras van mana straal naar bloeddorstig. Het bevindt zich nu op het corrupte bloed van alle wezens waar het zijn vele tanden in kan laten zakken.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251283] = {name = "Albino Mana Ray", additional_info = "1.5 sec cast [q]Summons en ontslaat een Albino Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie. [q]\"De verbrijzeling van Argus zorgde ervoor dat de mana stralen muteren en zich aanpassen aan hun omgeving. Sommigen van hen verlieten hun pigmenten om hun zintuigen te versterken.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251284] = {name = "Luminous Mana Ray", additional_info = "1.5 sec cast [q]Summons en ontslaat een Luminous Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie. [q]\"Mana stralen kunnen een heldere gloed uitstralen om prooi te lokken.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251292] = {name = "Plaatsing", additional_info = nil}
MultiLanguageSpellData['nl'][1251295] = {name = "Twilight Courser", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Om roofdieren te ontlopen, dimt deze cursus zijn hoorn terwijl hij zich verbergt en flitst met schitterende stralen wanneer hij wordt uitgelokt.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251297] = {name = "Gouden Sunrunner", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Deze vrije geest geniet van lange drafjes op het strand en zwerft door verschillende bloemenvelden.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251298] = {name = "Turquoise Courser", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Genoemd om zijn uniek gekleurde ogen die lijken te doordringen van je ziel, de turquoise cursusler toont meer intelligentie dan haar droomrunner neven en staat bekend als een uitstekende rechter van het karakter.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251300] = {name = "Gloomdark Nachtmerrie", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Aangeraakt door de Emerald Nightmare, is de aanwezigheid van dit schepsel in zijn dromen een voorteken van ongeluk. Om er één te zien terwijl wakkere een absolute catastrofe betekent.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251305] = {name = "Bonesteed of Triumph", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Een goed oorlogspaard is loyaal aan zijn botten. Na zijn sterfelijke rol te hebben afgeschud, is dit paard een voorteken van gedurfde verovering.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251307] = {name = "Bonesteed of Bloodshed", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Een goed oorlogspaard is loyaal aan zijn botten. Na zijn sterfelijke spiraal te hebben afgeschud, is dit paard een voorteken van eeuwige strijd.\" World Event: WO Remix: Legion"}
MultiLanguageSpellData['nl'][1251309] = {name = "Bonesteed of Plague", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Een goed oorlogspaard is loyaal aan zijn botten. Na zijn sterfelijke spiraal te hebben afgeschud, is dit paard een voorteken van ziekte en lijden.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251311] = {name = "Bonesteed of Oblivion", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Een goed oorlogspaard is loyaal aan zijn botten. Na zijn sterfelijke rol te hebben afgeschud, is dit paard een voorteken van schaarste en dood.\" World Event: WoW Remix: Legion"}
