MultiLanguageSpellData['nl'][1251396] = {name = "Longhorned Sable Talbuk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De talkbuks van Argus zijn gegroeid lange, grove vacht van briljante kleuren die de tinten van hun gebroken planeet weerspiegelt.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251397] = {name = "Garnet Ruinstrider", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Uitgerust met stevige barden, dragen Argussiaanse ruinestriders zonder angst hun renners over het gebroken afval van Argus en daarbuiten.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251398] = {name = "Longhorned Bleakhoof Talbuk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Gesneeuwd door de chaos veroorzaakt door decennia van conflict, is dit fel-infused paard een perfecte match voor een onverschrokken avonturier.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251399] = {name = "Longhorned Argussian Talbuk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Enkele talbuks wisten ongedeerd te blijven ondanks de uitbuiting van hun thuiswereld door het Legioen. Hun vasthoudendheid past bij een nobel paard.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1251400] = {name = "Longhorned Beryl Talbuk", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Deze wilde talbuk gevonden tussen de ruïnes van Argus heeft overleefd en volhard door decennia van strijd.\" World Event: WoW Remix: Legion"}
