MultiLanguageSpellData['nl'][1255154] = {name = "Afsluiten catch up", additional_info = "Instant [q]Als u verdwaald bent, probeer dan Peruse Tome te teleporteren naar het juiste gebied. Het verlaten van Catch Up zal je terug teleporteren naar je hoofdstad. U zult in staat zijn om deze Catch Up Campaign opnieuw te hervatten op elk moment, tenzij u een andere start. Wilt u doorgaan?"}
