MultiLanguageSpellData['nl'][1255159] = {name = "Mechanisch Prototype Panther MK-0", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"Toen Gadgetzan burgers het ondergrondse lab van het Gazlowe paleis openden, stikten de gebrul van gekooide beesten. Undermine tech versmolten gevechtsmodules op deze panters, waardoor bovenmenselijke kracht en snelheid. Rustbolt ingenieurs herprogrammeerden ze uitsluitend voor krijgers die campagne voeren in K'aresh. Vergeet niet om modules te ruilen op het Morphing Forum voordat de implementatie.\" In-Game Shop"}
MultiLanguageSpellData['nl'][1255165] = {name = "Raadpleeg de Tome", additional_info = "{Instant} {4 sec cooldown} [q]Query de Tome over waar te gaan volgende of voor meer informatie."}
MultiLanguageSpellData['nl'][1255179] = {name = "Staal Prototype Panther MK-0", additional_info = "1.5 sec cast [q]Summons en verwerpt deze mount. [q]\"De eerste Steel Horde soldaten die de Dark Portal overstaken, veroverden een woeste nachtzwaard. Blackrock artisanale bewapende het met magmapantser, transformeerde het in een gevechtswapen. Krijgers kunnen haar onderdelen aanpassen op het Morphing Forum aan hun vechtstijl en domineren het slagveld.\" In-Game Shop"}
