MultiLanguageSpellData['nl'][1255246] = {name = "Starspark Netherdrake", additional_info = "1.5 sec cast [q]Summons en ontslaat deze vliegende mount. [q]\"Na het vliegen u naar het einde van Outland en verder, de onderwater Drake werd uiteindelijk getrokken naar de blauwe lucht van Azeroth ook.\" Promotie: Burning Crusade Classic"}
