MultiLanguageSpellData['nl'][1255456] = {name = "Felscorned Wolfhawk", additional_info = "1.5 sec cast [q]Summons en verwerpt uw Felscorned Wolfhawk. Deze berg is alleen beschikbaar voor Hunters. [q]\"Gesneeuwd door de oorlog op de Broken Eilanden, verdient deze Wolfhawk een goed thuis.\" World Event: WoW Remix: Legion"}
MultiLanguageSpellData['nl'][1255463] = {name = "Archmage's Felscorned Disc", additional_info = "1.5 sec cast [q]Summons en verwerpt de Felscorned Disc van uw aartsmage. Deze mount is alleen beschikbaar voor Mages. [q]\"Sommigen zeggen dat magie \"vluchtig\" of \"corrupt\" of \"verboden\" is. Sommige magen zijn verkeerd.\" World Event: WoW Remix: Legion"}
